//! Registry of v1 Paideia-template staking contracts eligible for permissionless
//! stake recovery.
//!
//! Two redemption mechanisms are registered here, one per [`RecoveryMechanism`]
//! variant, with differing stake-key handling:
//!
//! - **[`RecoveryMechanism::Direct`]** (Ergopad, EGIO): both share the *same*
//!   StakeBox / StakeStateBox script templates (verified byte-identical code
//!   bodies — only the embedded token/NFT constants differ). The StakeBox script
//!   only requires that *some* input in the redeeming tx carries the token whose
//!   ID equals the StakeBox R5 (the stake-key NFT); the key is **neither burned
//!   nor moved** — it flows back through the change output to the signer.
//! - **[`RecoveryMechanism::PaideiaProxy`]** (Paideia's own v1 staking): a
//!   structurally different contract family (StakeBox `101f` / StakeStateBox
//!   `104e`, different opcode bodies). Unstaking is not a direct "combine the key
//!   box with the state box" spend; it routes through a single-use **unstake
//!   proxy** box (`101b`) that carries the stake key and names a payout recipient
//!   in its R5. On a successful unstake the key **is burned** (consumed by the
//!   executor tx); it is never a one-way trap, though — the proxy's equally
//!   permissionless *refund* path returns the key (and the ERG) to the recipient
//!   if the unstake can't run. See [`crate::tx_builder`] for the two-step
//!   (proxy-create → unstake) flow and the on-chain evidence (`tx_builder`
//!   oracle tests) proving both StakeBox/StakeStateBox and the proxy are gated
//!   purely structurally (no signature/PK check anywhere; a real unstake spent
//!   all three inputs with empty proofs).

/// How a stake position is redeemed once its live StakeBox is located.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RecoveryMechanism {
    /// Ergopad/EGIO: the StakeBox script only requires that *some input* in the
    /// redeeming tx carries the R5 stake-key NFT. A single 3-input tx
    /// (StakeStateBox, StakeBox, user key box) unstakes and returns the key via
    /// change. Built by [`crate::tx_builder::build_recovery_tx_eip12`].
    Direct,
    /// Paideia v1: unstaking is mediated by a single-use proxy box at the `101b`
    /// contract. The key holder first spends their key box into a proxy box
    /// (R4 = reward amount, R5 = payout recipient ergotree bytes), then the proxy
    /// is consumed together with the StakeStateBox and the matching StakeBox to pay
    /// the reward to the recipient (the stake key is burned). No signature is
    /// required to *execute* the unstake — only to create the proxy from the user's
    /// own wallet. Built by [`crate::tx_builder::build_paideia_proxy_tx`].
    PaideiaProxy,
}

/// Static configuration for one v1 staking pool on the shared Paideia template.
///
/// `stake_box_ergo_tree` / `stake_state_ergo_tree` are retained for provenance and
/// future structural validation; box discovery keys off the P2S *address* (reliably
/// indexed by `unspent_boxes_by_address` on extraIndex nodes).
#[derive(Debug, Clone, Copy)]
pub struct StakeProtocolConfig {
    /// Human-facing protocol name, e.g. `"Ergopad"`.
    pub name: &'static str,
    /// Reward-token ticker shown in the UI, e.g. `"ERGOPAD"`.
    pub reward_token_name: &'static str,
    /// v1 StakeBox P2S address (full).
    pub stake_box_address: &'static str,
    /// v1 StakeStateBox P2S address (full).
    pub stake_state_address: &'static str,
    /// ErgoTree of the v1 StakeBox (provenance / structural reference).
    pub stake_box_ergo_tree: &'static str,
    /// ErgoTree of the v1 StakeStateBox (provenance / structural reference).
    pub stake_state_ergo_tree: &'static str,
    /// Singleton NFT identifying the unique StakeStateBox.
    pub stake_state_nft: &'static str,
    /// Pool-wide stake token. One unit per active StakeBox; remainder in the state box.
    pub stake_token: &'static str,
    /// The reward token released on unstake.
    pub reward_token: &'static str,
    /// Reward-token decimals (for display formatting only).
    pub reward_decimals: u32,
    /// How this pool is redeemed (chooses the tx builder). See [`RecoveryMechanism`].
    pub mechanism: RecoveryMechanism,
}

