/// All registered recoverable staking protocols. Scans try each in turn.
pub const PROTOCOLS: &[StakeProtocolConfig] = &[ERGOPAD, EGIO, PAIDEIA];

/// Look up a registered protocol by its human name (case-insensitive).
pub fn protocol_by_name(name: &str) -> Option<&'static StakeProtocolConfig> {
    PROTOCOLS.iter().find(|p| p.name.eq_ignore_ascii_case(name))
}

pub const MIN_MINER_FEE: u64 = citadel_core::constants::TX_FEE_NANO as u64;
pub const MIN_BOX_VALUE: u64 = citadel_core::constants::MIN_BOX_VALUE_NANO as u64;
pub const MIN_CHANGE_VALUE: u64 = 1_000_000;

// ----- Paideia proxy (PaideiaProxy mechanism) -----
// Constants for the single-use unstake proxy contract (`101b`). The proxy carries the
// stake key, R4 = [reward amount to unstake], R5 = payout recipient ergotree bytes.
// Verified against on-chain unstake tx
// `fccb0c4979d43295a27af7be0da3aa93db840776979621bee7c13a1b51c3cf97` (see the
// `tx_builder` oracle tests). Both spend paths of `101b` send value to the R5
// recipient — the primary (unstake) path pays out the reward, and the fallback path
// refunds the key + ERG to R5 — so a proxy funded to the recipient's own address is
// never a one-way trap.

/// P2S ergotree (hex) of the Paideia unstake proxy contract `101b`. Used as the
/// `ergo_tree` of the proxy output when creating a recovery proxy box.
pub const PAIDEIA_PROXY_ERGO_TREE: &str = "";

/// P2S address of the Paideia unstake proxy contract `101b`.
pub const PAIDEIA_PROXY_ADDRESS: &str = "";

/// ERG (nanoERG) to fund a Paideia unstake proxy box. Mirrors the on-chain oracle
/// (0.113 ERG): it covers the 0.1 ERG executor-incentive output plus the recipient
/// min-box and miner fee that the executing (unstake) tx must produce.
pub const PAIDEIA_PROXY_VALUE: u64 = 113_000_000;

// ----- Paideia executor (step 2 of 2: the permissionless unstake) -----
// The proxy `101b` unstake branch fires when INPUTS(0) is the StakeStateBox and pins
// three output values exactly (proxy constants c16/c18/c20) plus OUTPUTS.size == 5:
//   OUTPUTS(2).value == 100_000_000  AND  blake2b256(OUTPUTS(2).script) == <102f hash>
//   OUTPUTS(3).value ==   2_000_000  (script FREE → executor's own tip address)
//   OUTPUTS(4).value ==   2_000_000  (the miner fee box)
// The reward box OUTPUTS(1) is pinned only by `.script == proxy.R5`; its ERG value is
// whatever conservation leaves over, and its reward-token amount is fixed by the
// StakeStateBox/StakeBox scripts. Verified byte-for-byte against the real unstake tx
// `fccb0c4979d43295a27af7be0da3aa93db840776979621bee7c13a1b51c3cf97` (see the
// `tx_builder` oracle tests). Every input in that tx spent with an EMPTY proof: the
// unstake needs no signature from anyone.

/// The fixed `102f` executor-incentive contract's full ErgoTree (hex). The proxy's
/// unstake branch requires `blake2b256(OUTPUTS(2).propositionBytes)` to equal the proxy
/// constant `f43ce986…`; this is the exact preimage (verified: its blake2b256 hash
/// equals that constant). The incentive box carries no tokens and no registers.
pub const PAIDEIA_INCENTIVE_ERGO_TREE: &str = "";

/// Fixed incentive-box value the proxy pins for `OUTPUTS(2)` (0.1 ERG).
pub const PAIDEIA_INCENTIVE_VALUE: u64 = 100_000_000;

/// Fixed value the proxy pins for both `OUTPUTS(3)` (executor tip, script free) and
/// `OUTPUTS(4)` (miner fee) on the unstake path (0.002 ERG each).
pub const PAIDEIA_EXECUTOR_OUT_VALUE: u64 = 2_000_000;

/// The miner fee the proxy's *refund* branch leaves for `OUTPUTS(1)`: the refund pins
/// `OUTPUTS(0).value == SELF.value - 1_000_000`, so exactly 0.001 ERG remains for the
/// fee. Real refunds at 0.001 ERG are accepted on-chain (see the refund oracle test).
pub const PAIDEIA_REFUND_FEE: u64 = 1_000_000;

/// Pagination for `unspent_boxes_by_address` when scanning a stake P2S.
pub const STAKE_BOX_PAGE_SIZE: u64 = 500;
/// Upper bound on pages to scan per protocol (500 × 20 = 10,000 boxes).
pub const STAKE_BOX_MAX_PAGES: u64 = 20;
